    """
    Validates a URL for security and correctness:
    - Ensures scheme is HTTP or HTTPS
    - Ensures hostname is present
    - Processes internationalized domain names (IDN)
    - Verifies the hostname resolves to public, non-private IP addresses
    Raises urllib.error.URLError with a descriptive message if validation fails.
    """
    parsed_url = urlparse(url)
    # Validate URL scheme
    if parsed_url.scheme not in ("http", "https"):
        raise urllib.error.URLError(
            f"Invalid URL scheme '{parsed_url.scheme}': only HTTP and HTTPS are supported"
        )
    # Extract and validate hostname
    host = parsed_url.hostname
    port = parsed_url.port
    if not host:
        raise urllib.error.URLError("Invalid URL: missing hostname")
    # Convert internationalized domain names to punycode
    try:
        host = host.encode("idna").decode("ascii")
    except UnicodeError:
        raise urllib.error.URLError(
            "Invalid hostname: unable to process internationalized domain name"
        ) from None
    # Resolve hostname to IP addresses and validate they are public
    try:
        # Use default port for the scheme if not specified
        default_port = 443 if parsed_url.scheme == "https" else 80
        addrinfo = socket.getaddrinfo(host, port or default_port)
        # Extract unique IP addresses from the resolution results
        resolved_ips = {addr[4][0] for addr in addrinfo}
        for ip_str in resolved_ips:
            try:
                ip = ipaddress.ip_address(ip_str)
                # Block non-public IP ranges
                if (
                    ip.is_private
                    or ip.is_loopback
                    or ip.is_link_local
                    or ip.is_reserved
                    or ip.is_multicast
                ):
                    raise urllib.error.URLError(
                        f"Access blocked: hostname '{host}' resolves to non-public IP {ip_str}"
                    )
            except ValueError:
                raise urllib.error.URLError(
                    f"Invalid IP address '{ip_str}' resolved for hostname '{host}'"
                ) from None
    except socket.gaierror:
        raise urllib.error.URLError(f"Failed to resolve hostname: '{host}'") from None
    except socket.error as e:
        raise urllib.error.URLError(
            f"Network error while resolving hostname '{host}': {str(e)}"
        ) from None

